module TableStatus =
  struct
    type nonrec t =
      | CREATING 
      | UPDATING 
      | DELETING 
      | ACTIVE 
      | INACCESSIBLE_ENCRYPTION_CREDENTIALS 
      | ARCHIVING 
      | ARCHIVED 
      | Non_static_id of string 
    let make i = i
    let to_string =
      function
      | CREATING -> "CREATING"
      | UPDATING -> "UPDATING"
      | DELETING -> "DELETING"
      | ACTIVE -> "ACTIVE"
      | INACCESSIBLE_ENCRYPTION_CREDENTIALS ->
          "INACCESSIBLE_ENCRYPTION_CREDENTIALS"
      | ARCHIVING -> "ARCHIVING"
      | ARCHIVED -> "ARCHIVED"
      | Non_static_id s -> s
    let of_string =
      function
      | "CREATING" -> CREATING
      | "UPDATING" -> UPDATING
      | "DELETING" -> DELETING
      | "ACTIVE" -> ACTIVE
      | "INACCESSIBLE_ENCRYPTION_CREDENTIALS" ->
          INACCESSIBLE_ENCRYPTION_CREDENTIALS
      | "ARCHIVING" -> ARCHIVING
