  struct
    type nonrec t =
      {
      exportDescription: ExportDescription.t option
        [@ocaml.doc "Represents the properties of the export."]}
    type nonrec error =
      [ `ExportNotFoundException of ExportNotFoundException.t 
      | `InternalServerError of InternalServerError.t 
      | `LimitExceededException of LimitExceededException.t 
      | `Unknown_operation_error of (string * string option) ]
    let make ?exportDescription = fun () -> { exportDescription }
    let error_of_json name json =
      match name with
      | "ExportNotFoundException" ->
          `ExportNotFoundException (ExportNotFoundException.of_json json)
      | "InternalServerError" ->
          `InternalServerError (InternalServerError.of_json json)
      | "LimitExceededException" ->
          `LimitExceededException (LimitExceededException.of_json json)
      | name ->
          `Unknown_operation_error
            (name, (Some (Yojson.Safe.to_string json)))
    let error_of_xml name xml =
      match name with
      | "ExportNotFoundException" ->
          `ExportNotFoundException (ExportNotFoundException.of_xml xml)
      | "InternalServerError" ->
          `InternalServerError (InternalServerError.of_xml xml)
      | "LimitExceededException" ->
          `LimitExceededException (LimitExceededException.of_xml xml)
      | name ->
          `Unknown_operation_error (name, (Some (Awso.Xml.to_string xml)))
    let error_to_json : error -> Yojson.Safe.t =
      function
      | `ExportNotFoundException e ->
          `Assoc
            [("error", (`String "ExportNotFoundException"));
            ("details", (ExportNotFoundException.to_json e))]
      | `InternalServerError e ->
          `Assoc
            [("error", (`String "InternalServerError"));
            ("details", (InternalServerError.to_json e))]
      | `LimitExceededException e ->
          `Assoc
            [("error", (`String "LimitExceededException"));
            ("details", (LimitExceededException.to_json e))]
      | `Unknown_operation_error (code, msg) ->
          `Assoc (("error", (`String code)) ::
            ((match msg with
              | None -> []
              | Some m -> [("message", (`String m))])))
